import React from 'react';
import { View, Text, StyleSheet, Image, TouchableOpacity } from 'react-native';
import dayjs from 'dayjs';

export default function PostCard({ post, onReact }) {
  const username = post.author_name || post.author?.name || 'Unknown';
  const text = post.text || '';
  const created = post.created_at ? dayjs(post.created_at).fromNow ? dayjs(post.created_at).fromNow() : post.created_at : '';

  return (
    <View style={styles.card}>
      <View style={styles.header}>
        <View style={styles.avatar} />
        <View style={{ flex: 1 }}>
          <Text style={styles.username}>{username}</Text>
          <Text style={styles.time}>{post.created_at || ''}</Text>
        </View>
        <TouchableOpacity onPress={onReact} style={styles.reactBtn}>
          <Text style={styles.reactText}>❤️</Text>
        </TouchableOpacity>
      </View>
      <View style={styles.content}>
        <Text style={styles.text}>{text}</Text>
      </View>
    </View>
  );
}

const styles = StyleSheet.create({
  card: { padding: 12, borderBottomWidth: 1, borderColor: '#eee', backgroundColor: '#fff' },
  header: { flexDirection: 'row', alignItems: 'center' },
  avatar: { width: 40, height: 40, borderRadius: 20, backgroundColor: '#ddd', marginRight: 8 },
  username: { fontWeight: '600' },
  time: { color: '#666', fontSize: 12 },
  reactBtn: { padding: 8 },
  reactText: { fontSize: 18 },
  content: { marginTop: 8 },
  text: { fontSize: 15, lineHeight: 20 }
});
